{
  "name": "Wise Analyst",
  "description": "Dashboard financeiro inteligente para revenda de recargas e dados móveis, com análise de lucro, importação de CSV e visualizações gráficas avançadas."
}

export interface RawTransaction {
  Data: string;
  Operadora: string;
  Cliente: string;
  Pacote: string;
  "Valor Venda": string;
  Custo?: string;
  Lucro?: string;
  Status: string;
}

export interface Transaction {
  id: string;
  date: string; // ISO String YYYY-MM-DD
  operator: string;
  client: string;
  package: string;
  saleValue: number;
  cost: number;
  profit: number;
  status: 'Pago' | 'Pendente' | 'Falha' | string;
}

export interface DashboardStats {
  totalRevenue: number;
  totalProfit: number;
  totalCost: number;
  salesCount: number;
  avgTicket: number;
  topPackages: Array<{ name: string; value: number }>;
  topOperators: Array<{ name: string; value: number }>;
  revenueOverTime: Array<{ date: string; value: number; profit: number }>;
  statusDistribution: Array<{ name: string; value: number }>;
  topClients: Array<{ name: string; totalSpent: number; transactions: number }>;
}

export enum SortField {
  DATE = 'date',
  SALE_VALUE = 'saleValue',
  PROFIT = 'profit',
  CLIENT = 'client'
}

export enum SortDirection {
  ASC = 'asc',
  DESC = 'desc'
}

import { Transaction, DashboardStats, RawTransaction } from '../types';

// Formata moeda para Metical Moçambicano
export const formatCurrency = (value: number): string => {
  return new Intl.NumberFormat('pt-MZ', {
    style: 'currency',
    currency: 'MZN',
  }).format(value);
};

// Gera um ID único simples
const generateId = () => Math.random().toString(36).substr(2, 9);

// Normaliza data para YYYY-MM-DD
const normalizeDate = (dateStr: string): string => {
  // Tenta formatos comuns: DD/MM/YYYY, YYYY-MM-DD
  if (!dateStr) return new Date().toISOString().split('T')[0];

  if (dateStr.includes('/')) {
    const parts = dateStr.split('/');
    if (parts.length === 3) {
      // Assume DD/MM/YYYY
      return `${parts[2]}-${parts[1].padStart(2, '0')}-${parts[0].padStart(2, '0')}`;
    }
  }
  return dateStr.split('T')[0];
};

// Regras de Negócio para Cálculo de Lucro
const calculateEconomics = (pkg: string, saleVal: number, costStr?: string, profitStr?: string) => {
  let cost = costStr ? parseFloat(costStr.replace(',', '.')) : 0;
  let profit = profitStr ? parseFloat(profitStr.replace(',', '.')) : 0;
  const sale = saleVal;

  // Se o Lucro já veio no CSV, usa ele (assumindo prioridade aos dados importados)
  if (!profitStr && !costStr) {
    const pkgLower = pkg.toLowerCase();

    // Regras Específicas
    if (pkgLower.includes('crédito 500')) {
      profit = 90;
      cost = sale - profit;
    } else if (pkgLower.includes('1024mb')) {
      profit = 6;
      cost = sale - profit;
    } else if (pkgLower.includes('5gb')) {
      profit = 20;
      cost = sale - profit;
    } else {
      // Regra Geral: 15% de margem
      profit = sale * 0.15;
      cost = sale - profit;
    }
  } else if (!profitStr && costStr) {
     // Se temos custo mas não lucro
     profit = sale - cost;
  } else if (profitStr && !costStr) {
      // Se temos lucro mas não custo
      cost = sale - profit;
  }

  return { cost, profit };
};

// Parser de CSV
export const parseCSV = (csvText: string): Transaction[] => {
  const lines = csvText.trim().split('\n');
  if (lines.length < 2) return [];

  // Detectar delimitador
  const headerLine = lines[0];
  const delimiter = headerLine.includes(';') ? ';' : ',';

  const headers = headerLine.split(delimiter).map(h => h.trim().replace(/"/g, ''));

  const transactions: Transaction[] = [];

  for (let i = 1; i < lines.length; i++) {
    const currentLine = lines[i].trim();
    if (!currentLine) continue;

    // Split simples ignorando vírgulas dentro de aspas (básico)
    // Para simplificar, assumiremos split pelo delimitador detectado
    const values = currentLine.split(delimiter).map(v => v.trim().replace(/"/g, ''));

    // Mapear colunas dinamicamente baseado no header
    const row: any = {};
    headers.forEach((header, index) => {
      row[header] = values[index];
    });

    // Mapeamento para interface Transaction
    const saleValue = parseFloat((row['Valor Venda'] || '0').replace(',', '.'));
    const { cost, profit } = calculateEconomics(
      row['Pacote'] || '',
      saleValue,
      row['Custo'],
      row['Lucro']
    );

    transactions.push({
      id: generateId(),
      date: normalizeDate(row['Data'] || ''),
      operator: row['Operadora'] || 'Outros',
      client: row['Cliente'] || 'Desconhecido',
      package: row['Pacote'] || 'Geral',
      saleValue: saleValue,
      cost: Number(cost.toFixed(2)),
      profit: Number(profit.toFixed(2)),
      status: row['Status'] || 'Pendente'
    });
  }

  return transactions;
};

// Agregação de Dados para Dashboard
export const calculateStats = (data: Transaction[]): DashboardStats => {
  const totalRevenue = data.reduce((acc, curr) => acc + curr.saleValue, 0);
  const totalProfit = data.reduce((acc, curr) => acc + curr.profit, 0);
  const totalCost = data.reduce((acc, curr) => acc + curr.cost, 0);
  const salesCount = data.length;
  const avgTicket = salesCount > 0 ? totalRevenue / salesCount : 0;

  // Top Packages
  const pkgMap = new Map<string, number>();
  data.forEach(t => {
    pkgMap.set(t.package, (pkgMap.get(t.package) || 0) + 1);
  });
  const topPackages = Array.from(pkgMap.entries())
    .map(([name, value]) => ({ name, value }))
    .sort((a, b) => b.value - a.value)
    .slice(0, 10);

  // Top Operators
  const opMap = new Map<string, number>();
  data.forEach(t => {
    opMap.set(t.operator, (opMap.get(t.operator) || 0) + 1);
  });
  const topOperators = Array.from(opMap.entries())
    .map(([name, value]) => ({ name, value }));

  // Revenue Over Time
  const dateMap = new Map<string, { revenue: number; profit: number }>();
  data.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .forEach(t => {
        const current = dateMap.get(t.date) || { revenue: 0, profit: 0 };
        dateMap.set(t.date, { 
          revenue: current.revenue + t.saleValue,
          profit: current.profit + t.profit
        });
      });
  const revenueOverTime = Array.from(dateMap.entries())
    .map(([date, val]) => ({ 
      date, 
      value: Number(val.revenue.toFixed(2)),
      profit: Number(val.profit.toFixed(2))
    }));

  // Status Distribution
  const statusMap = new Map<string, number>();
  data.forEach(t => {
    statusMap.set(t.status, (statusMap.get(t.status) || 0) + 1);
  });
  const statusDistribution = Array.from(statusMap.entries())
    .map(([name, value]) => ({ name, value }));

  // Top Clients
  const clientMap = new Map<string, { spent: number; count: number }>();
  data.forEach(t => {
    const current = clientMap.get(t.client) || { spent: 0, count: 0 };
    clientMap.set(t.client, {
      spent: current.spent + t.saleValue,
      count: current.count + 1
    });
  });
  const topClients = Array.from(clientMap.entries())
    .map(([name, val]) => ({ name, totalSpent: val.spent, transactions: val.count }))
    .sort((a, b) => b.totalSpent - a.totalSpent)
    .slice(0, 5);

  return {
    totalRevenue,
    totalProfit,
    totalCost,
    salesCount,
    avgTicket,
    topPackages,
    topOperators,
    revenueOverTime,
    statusDistribution,
    topClients
  };
};

import React from 'react';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  BarChart, Bar, Legend, PieChart, Pie, Cell
} from 'recharts';
import { formatCurrency } from '../utils/helpers';

const COLORS = ['#10b981', '#3b82f6', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];
const STATUS_COLORS: Record<string, string> = {
  'Pago': '#10b981', // Green
  'Pendente': '#f59e0b', // Amber
  'Falha': '#ef4444', // Red
};

