// Formata moeda para Metical Moçambicano
export const formatCurrency = (value: number): string => {
  return new Intl.NumberFormat('pt-MZ', {
    style: 'currency',
    currency: 'MZN',
  }).format(value);
};

// Gera um ID único simples
const generateId = () => Math.random().toString(36).substr(2, 9);

// Normaliza data para YYYY-MM-DD
// Suporta "DD/MM/YYYY", "DD/MM/YYYY, HH:mm:ss", "YYYY-MM-DD"
const normalizeDate = (dateStr: string): string => {
  if (!dateStr) return new Date().toISOString().split('T')[0];

  // Remove hora se existir (separa por vírgula ou espaço)
  let cleanDate = dateStr;
  if (dateStr.includes(',')) {
    cleanDate = dateStr.split(',')[0].trim();
  } else if (dateStr.includes(' ') && dateStr.includes(':')) {
    // Caso simples de data espaço hora sem virgula
    cleanDate = dateStr.split(' ')[0].trim();
  }

  if (cleanDate.includes('/')) {
    const parts = cleanDate.split('/');
    if (parts.length === 3) {
      // Assume DD/MM/YYYY
      return `${parts[2]}-${parts[1].padStart(2, '0')}-${parts[0].padStart(2, '0')}`;
    }
  }
  return cleanDate.split('T')[0];
};

// Remove aspas e espaços extras
const cleanValue = (val: string) => val ? val.trim().replace(/"/g, '') : '';

// Parser numérico robusto (aceita . ou ,)
const parseMoney = (val: string | undefined): number => {
  if (!val) return 0;
  // Remove espaços e símbolo de moeda se houver (embora o CSV pareça limpo de símbolos)
  const clean = cleanValue(val);
  // Se tiver vírgula e ponto, assume formato 1.000,00 ou 1,000.00
  // O CSV fornecido usa . para decimais (ex: 450.00), mas o prompt original falava em CSV local.
  // Vamos assumir que se houver vírgula, ela pode ser decimal se não houver ponto depois.
  return parseFloat(clean.replace(',', '.'));
};

// Regras de Negócio para Cálculo de Lucro
const calculateEconomics = (pkg: string, saleVal: number, costVal: number, profitVal: number) => {
  let cost = costVal;
  let profit = profitVal;
  const sale = saleVal;

  // Se o Lucro/Custo vieram zerados ou inválidos do CSV, tentamos calcular
  // Nota: O CSV fornecido tem colunas explícitas, então usamos os valores diretos se > 0 ou se existirem
  // Mas como parseMoney retorna 0 se undefined, precisamos verificar se a lógica de negócio deve sobrepor.
  // A regra diz: "Se o CSV não tiver a coluna 'Lucro' ou 'Custo', o sistema deve calcular".
  // Vamos assumir que se o CSV tem valores, confiamos neles. Se forem 0 e a venda > 0, talvez recalculamos?
  // O CSV exemplo tem Lucro 0.00 para alguns pacotes Movitel Ilimitado. Nesse caso, Lucro é 0 mesmo.
  // Então só calculamos se não tivermos a informação (ex: colunas não mapeadas).

  if (profit === 0 && cost === 0 && sale > 0) {
     // Check if it really should be calculated or if it is just zero profit data.
     // Para garantir, vamos aplicar a regra APENAS se os valores originais não foram encontrados/mapeados
     // Mas como passamos os valores parseados, vamos assumir que o CSV é a fonte da verdade.
     // Mude a lógica abaixo APENAS se quiser forçar o cálculo.
     // Pelo prompt: "Se o CSV não tiver a coluna... calcular automaticamente".
     // Vou manter a lógica de cálculo apenas como fallback se a coluna não existir.
  }

  // Fallback se custo e lucro forem estritamente zero e parecer que faltou dado (ex: regra de negócio hardcoded)
  // No entanto, para o CSV fornecido, os dados parecem completos.
  // Vou deixar a função retornar o que veio do CSV, mas se fosse necessário:
  /*
  if (profit === 0 && cost === 0 && sale > 0) {
    const pkgLower = pkg.toLowerCase();
    if (pkgLower.includes('crédito 500')) profit = 90;
    else if (pkgLower.includes('1024mb')) profit = 6;
    else if (pkgLower.includes('5gb')) profit = 20;
    else profit = sale * 0.15;
    cost = sale - profit;
  }
  */

  // Se só temos venda e lucro, calculamos custo. Se só venda e custo, calculamos lucro.
  if (profit > 0 && cost === 0) cost = sale - profit;
  if (cost > 0 && profit === 0) profit = sale - cost;

  return { cost, profit };
};

// Parser de CSV
export const parseCSV = (csvText: string): Transaction[] => {
  const lines = csvText.trim().split('\n');
  if (lines.length < 2) return [];

  // Detectar delimitador
  const headerLine = lines[0].replace(/^\uFEFF/, ''); // Remove BOM se existir
  const delimiter = headerLine.includes(';') ? ';' : ',';

  const headers = headerLine.split(delimiter).map(h => h.trim().replace(/"/g, ''));

  // Helper para encontrar valor por nome da coluna (case insensitive e parcial)
  const getColIndex = (search: string[]) => {
    return headers.findIndex(h => search.some(s => h.toLowerCase() === s.toLowerCase() || h.toLowerCase().includes(s.toLowerCase())));
  };

  const idxDate = getColIndex(['Data']);
  const idxOperator = getColIndex(['Operadora']);
  const idxClient = getColIndex(['Cliente']);
  const idxPackage = getColIndex(['Pacote']);
  const idxCategory = getColIndex(['Categoria']);
  const idxSale = getColIndex(['Valor Venda', 'Venda']);
  const idxCost = getColIndex(['Custo']);
  const idxProfit = getColIndex(['Lucro']);
  const idxStatus = getColIndex(['Status']);

  const transactions: Transaction[] = [];

  for (let i = 1; i < lines.length; i++) {
    const currentLine = lines[i].trim();
    if (!currentLine) continue;

    const values = currentLine.split(delimiter).map(v => cleanValue(v));

    // Extração segura
    const getVal = (idx: number) => idx !== -1 ? values[idx] : '';

    const pkg = getVal(idxPackage) || 'Geral';
    const rawSale = parseMoney(getVal(idxSale));
    let rawCost = parseMoney(getVal(idxCost));
    let rawProfit = parseMoney(getVal(idxProfit));

    // Se as colunas de custo/lucro não existirem no CSV, aplica regra
    if (idxCost === -1 && idxProfit === -1) {
        const pkgLower = pkg.toLowerCase();
        if (pkgLower.includes('crédito 500')) {
            rawProfit = 90;
        } else if (pkgLower.includes('1024mb')) {
            rawProfit = 6;
        } else if (pkgLower.includes('5gb')) {
            rawProfit = 20;
        } else {
            rawProfit = rawSale * 0.15;
        }
        rawCost = rawSale - rawProfit;
    } else {
        // Ajuste de consistência básico
        const { cost, profit } = calculateEconomics(pkg, rawSale, rawCost, rawProfit);
        rawCost = cost;
        rawProfit = profit;
    }

    transactions.push({
      id: generateId(),
      date: normalizeDate(getVal(idxDate)),
      operator: getVal(idxOperator) || 'Outros',
      client: getVal(idxClient) || 'Desconhecido',
      package: pkg,
      category: getVal(idxCategory) || 'Geral',
      saleValue: rawSale,
      cost: Number(rawCost.toFixed(2)),
      profit: Number(rawProfit.toFixed(2)),
      status: getVal(idxStatus) || 'Pendente'
    });
  }

  return transactions;
};

// Agregação de Dados para Dashboard
export const calculateStats = (data: Transaction[]): DashboardStats => {
  const totalRevenue = data.reduce((acc, curr) => acc + curr.saleValue, 0);
  const totalProfit = data.reduce((acc, curr) => acc + curr.profit, 0);
  const totalCost = data.reduce((acc, curr) => acc + curr.cost, 0);
  const salesCount = data.length;
  const avgTicket = salesCount > 0 ? totalRevenue / salesCount : 0;

  // Helper para contagem
  const countByField = (field: keyof Transaction, limit = 10) => {
    const map = new Map<string, number>();
    data.forEach(t => {
      const val = String(t[field]);
      map.set(val, (map.get(val) || 0) + 1);
    });
    return Array.from(map.entries())
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, limit);
  };

  const topPackages = countByField('package', 10);
  const topOperators = countByField('operator', 10);
  const topCategories = countByField('category', 10);
  const statusDistribution = countByField('status', 10);

  // Revenue Over Time
  const dateMap = new Map<string, { revenue: number; profit: number }>();
  data.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .forEach(t => {
        const current = dateMap.get(t.date) || { revenue: 0, profit: 0 };
        dateMap.set(t.date, { 
          revenue: current.revenue + t.saleValue,
          profit: current.profit + t.profit
        });
      });
  const revenueOverTime = Array.from(dateMap.entries())
    .map(([date, val]) => ({ 
      date, 
      value: Number(val.revenue.toFixed(2)),
      profit: Number(val.profit.toFixed(2))
    }));

  // Top Clients
  const clientMap = new Map<string, { spent: number; count: number }>();
  data.forEach(t => {
    const current = clientMap.get(t.client) || { spent: 0, count: 0 };
    clientMap.set(t.client, {
      spent: current.spent + t.saleValue,
      count: current.count + 1
    });
  });
  const topClients = Array.from(clientMap.entries())
    .map(([name, val]) => ({ name, totalSpent: val.spent, transactions: val.count }))
    .sort((a, b) => b.totalSpent - a.totalSpent)
    .slice(0, 5);

  return {
    totalRevenue,
    totalProfit,
    totalCost,
    salesCount,
    avgTicket,
    topPackages,
    topOperators,
    topCategories,
    revenueOverTime,
    statusDistribution,
    topClients
  };
};

import React, { useState, useEffect } from 'react';
import { 
  Upload, Moon, Sun, TrendingUp, DollarSign, Users, 
  ShoppingCart, Activity, FileText, AlertCircle 
} from 'lucide-react';
